// UGO Landing Page - Bootstrap Bundle

// ===== BOOTSTRAP BUNDLE ===== */
window.bootstrap = {
    // ===== TOOLTIP ===== */
    Tooltip: function(element, options) {
        this.element = element;
        this.options = options || {};
        this.isVisible = false;
        
        this.show = function() {
            if (!this.isVisible) {
                this.createTooltip();
                this.isVisible = true;
            }
            return this;
        };
        
        this.hide = function() {
            if (this.isVisible) {
                this.removeTooltip();
                this.isVisible = false;
            }
            return this;
        };
        
        this.toggle = function() {
            if (this.isVisible) {
                this.hide();
            } else {
                this.show();
            }
            return this;
        };
        
        this.createTooltip = function() {
            const tooltip = document.createElement('div');
            tooltip.className = 'tooltip bs-tooltip-' + (this.options.placement || 'top');
            tooltip.innerHTML = `
                <div class="tooltip-arrow"></div>
                <div class="tooltip-inner">${this.options.title || this.element.getAttribute('title') || ''}</div>
            `;
            
            document.body.appendChild(tooltip);
            
            // Position tooltip
            const rect = this.element.getBoundingClientRect();
            const tooltipRect = tooltip.getBoundingClientRect();
            
            let top, left;
            switch (this.options.placement || 'top') {
                case 'top':
                    top = rect.top - tooltipRect.height - 10;
                    left = rect.left + (rect.width - tooltipRect.width) / 2;
                    break;
                case 'bottom':
                    top = rect.bottom + 10;
                    left = rect.left + (rect.width - tooltipRect.width) / 2;
                    break;
                case 'left':
                    top = rect.top + (rect.height - tooltipRect.height) / 2;
                    left = rect.left - tooltipRect.width - 10;
                    break;
                case 'right':
                    top = rect.top + (rect.height - tooltipRect.height) / 2;
                    left = rect.right + 10;
                    break;
            }
            
            tooltip.style.position = 'fixed';
            tooltip.style.top = top + 'px';
            tooltip.style.left = left + 'px';
            tooltip.style.zIndex = '1070';
            
            this.tooltipElement = tooltip;
        };
        
        this.removeTooltip = function() {
            if (this.tooltipElement) {
                this.tooltipElement.remove();
                this.tooltipElement = null;
            }
        };
        
        this.dispose = function() {
            this.hide();
            return this;
        };
    },
    
    // ===== DROPDOWN ===== */
    Dropdown: function(element) {
        this.element = element;
        this.menu = element.nextElementSibling;
        
        this.toggle = function() {
            if (this.menu && this.menu.classList.contains('dropdown-menu')) {
                this.menu.classList.toggle('show');
                this.element.classList.toggle('show');
                
                // Close other dropdowns
                document.querySelectorAll('.dropdown-menu.show').forEach(menu => {
                    if (menu !== this.menu) {
                        menu.classList.remove('show');
                    }
                });
                
                document.querySelectorAll('[data-bs-toggle="dropdown"].show').forEach(toggle => {
                    if (toggle !== this.element) {
                        toggle.classList.remove('show');
                    }
                });
            }
            return this;
        };
        
        this.show = function() {
            if (this.menu) {
                this.menu.classList.add('show');
                this.element.classList.add('show');
            }
            return this;
        };
        
        this.hide = function() {
            if (this.menu) {
                this.menu.classList.remove('show');
                this.element.classList.remove('show');
            }
            return this;
        };
        
        this.dispose = function() {
            this.hide();
            return this;
        };
    },
    
    // ===== MODAL ===== */
    Modal: function(element) {
        this.element = element;
        this.isVisible = false;
        
        this.show = function() {
            if (!this.isVisible) {
                this.element.style.display = 'block';
                this.element.classList.add('show');
                document.body.classList.add('modal-open');
                
                // Create backdrop
                if (!document.querySelector('.modal-backdrop')) {
                    const backdrop = document.createElement('div');
                    backdrop.className = 'modal-backdrop fade show';
                    document.body.appendChild(backdrop);
                }
                
                this.isVisible = true;
            }
            return this;
        };
        
        this.hide = function() {
            if (this.isVisible) {
                this.element.style.display = 'none';
                this.element.classList.remove('show');
                document.body.classList.remove('modal-open');
                
                // Remove backdrop
                const backdrop = document.querySelector('.modal-backdrop');
                if (backdrop) backdrop.remove();
                
                this.isVisible = false;
            }
            return this;
        };
        
        this.toggle = function() {
            if (this.isVisible) {
                this.hide();
            } else {
                this.show();
            }
            return this;
        };
        
        this.dispose = function() {
            this.hide();
            return this;
        };
    },
    
    // ===== ALERT ===== */
    Alert: function(element) {
        this.element = element;
        
        this.close = function() {
            this.element.style.transition = 'opacity 0.15s';
            this.element.style.opacity = '0';
            
            setTimeout(() => {
                this.element.remove();
            }, 150);
            return this;
        };
        
        this.dispose = function() {
            this.close();
            return this;
        };
    },
    
    // ===== COLLAPSE ===== */
    Collapse: function(element) {
        this.element = element;
        this.target = document.querySelector(element.getAttribute('data-bs-target') || element.getAttribute('href'));
        this.isExpanded = false;
        
        this.toggle = function() {
            if (this.isExpanded) {
                this.hide();
            } else {
                this.show();
            }
            return this;
        };
        
        this.show = function() {
            if (this.target && !this.isExpanded) {
                this.target.style.display = 'block';
                this.target.style.height = 'auto';
                const height = this.target.scrollHeight + 'px';
                this.target.style.height = '0';
                this.target.style.transition = 'height 0.35s ease';
                
                setTimeout(() => {
                    this.target.style.height = height;
                }, 10);
                
                this.element.classList.add('collapsed');
                this.element.setAttribute('aria-expanded', 'true');
                this.isExpanded = true;
            }
            return this;
        };
        
        this.hide = function() {
            if (this.target && this.isExpanded) {
                this.target.style.height = '0';
                this.target.style.transition = 'height 0.35s ease';
                
                setTimeout(() => {
                    this.target.style.display = 'none';
                }, 350);
                
                this.element.classList.remove('collapsed');
                this.element.setAttribute('aria-expanded', 'false');
                this.isExpanded = false;
            }
            return this;
        };
        
        this.dispose = function() {
            this.hide();
            return this;
        };
    },
    
    // ===== TAB ===== */
    Tab: function(element) {
        this.element = element;
        this.target = document.querySelector(element.getAttribute('data-bs-target') || element.getAttribute('href'));
        
        this.show = function() {
            // Hide all tabs
            const tabContainer = this.element.closest('.tab-content');
            if (tabContainer) {
                tabContainer.querySelectorAll('.tab-pane').forEach(pane => {
                    pane.classList.remove('show', 'active');
                });
            }
            
            // Remove active class from all nav links
            const navContainer = this.element.closest('.nav');
            if (navContainer) {
                navContainer.querySelectorAll('.nav-link').forEach(link => {
                    link.classList.remove('active');
                });
            }
            
            // Show current tab
            if (this.target) {
                this.target.classList.add('show', 'active');
            }
            this.element.classList.add('active');
            
            return this;
        };
        
        this.dispose = function() {
            return this;
        };
    },
    
    // ===== TOAST ===== */
    Toast: function(element) {
        this.element = element;
        this.isVisible = false;
        
        this.show = function() {
            if (!this.isVisible) {
                this.element.style.display = 'block';
                this.element.classList.add('show');
                this.isVisible = true;
                
                // Auto hide after 5 seconds
                setTimeout(() => {
                    this.hide();
                }, 5000);
            }
            return this;
        };
        
        this.hide = function() {
            if (this.isVisible) {
                this.element.classList.remove('show');
                setTimeout(() => {
                    this.element.style.display = 'none';
                }, 150);
                this.isVisible = false;
            }
            return this;
        };
        
        this.dispose = function() {
            this.hide();
            return this;
        };
    }
};

// ===== AUTO-INITIALIZATION ===== */
document.addEventListener('DOMContentLoaded', function() {
    // Initialize dropdowns
    document.querySelectorAll('[data-bs-toggle="dropdown"]').forEach(element => {
        element.addEventListener('click', function(e) {
            e.preventDefault();
            const dropdown = new bootstrap.Dropdown(element);
            dropdown.toggle();
        });
    });
    
    // Initialize tooltips
    document.querySelectorAll('[data-bs-toggle="tooltip"]').forEach(element => {
        const title = element.getAttribute('title') || element.getAttribute('data-bs-title');
        if (title) {
            new bootstrap.Tooltip(element, { title: title });
            
            element.addEventListener('mouseenter', function() {
                const tooltip = new bootstrap.Tooltip(element, { title: title });
                tooltip.show();
            });
            
            element.addEventListener('mouseleave', function() {
                const tooltip = new bootstrap.Tooltip(element, { title: title });
                tooltip.hide();
            });
        }
    });
    
    // Initialize modals
    document.querySelectorAll('.modal').forEach(element => {
        const modal = new bootstrap.Modal(element);
        
        // Close modal on backdrop click
        element.addEventListener('click', function(e) {
            if (e.target === element) {
                modal.hide();
            }
        });
        
        // Close modal on close button click
        element.querySelectorAll('[data-bs-dismiss="modal"]').forEach(closeBtn => {
            closeBtn.addEventListener('click', function() {
                modal.hide();
            });
        });
    });
    
    // Initialize alerts
    document.querySelectorAll('.alert .btn-close').forEach(element => {
        element.addEventListener('click', function() {
            const alert = new bootstrap.Alert(element.closest('.alert'));
            alert.close();
        });
    });
    
    // Initialize collapses
    document.querySelectorAll('[data-bs-toggle="collapse"]').forEach(element => {
        element.addEventListener('click', function(e) {
            e.preventDefault();
            const collapse = new bootstrap.Collapse(element);
            collapse.toggle();
        });
    });
    
    // Initialize tabs
    document.querySelectorAll('[data-bs-toggle="tab"]').forEach(element => {
        element.addEventListener('click', function(e) {
            e.preventDefault();
            const tab = new bootstrap.Tab(element);
            tab.show();
        });
    });
    
    // Initialize toasts
    document.querySelectorAll('.toast').forEach(element => {
        const toast = new bootstrap.Toast(element);
        
        // Auto show toast if it has show class
        if (element.classList.contains('show')) {
            toast.show();
        }
    });
    
    // Close dropdowns when clicking outside
    document.addEventListener('click', function(e) {
        if (!e.target.closest('[data-bs-toggle="dropdown"]') && !e.target.closest('.dropdown-menu')) {
            document.querySelectorAll('.dropdown-menu.show').forEach(menu => {
                menu.classList.remove('show');
            });
            document.querySelectorAll('[data-bs-toggle="dropdown"].show').forEach(toggle => {
                toggle.classList.remove('show');
            });
        }
    });
    
    // Handle ESC key for modals
    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape') {
            const openModal = document.querySelector('.modal.show');
            if (openModal) {
                const modal = new bootstrap.Modal(openModal);
                modal.hide();
            }
        }
    });
});

// ===== EXPORT ===== */
if (typeof module !== 'undefined' && module.exports) {
    module.exports = bootstrap;
}
